import java.nio.file.*;
import java.util.stream.*;
public class App {
    public static void main(String[] args) throws Exception {
        Path p = Path.of("data.txt");
        Files.writeString(p, "Line 1\nLine 2\n\nLine 4\nLine 5\n\nLine 7\nLine 8\nLine 9\nLine 10");

        long total, nonBlank;
        try (Stream<String> lines = Files.lines(p)) {
            total = lines.count();
        }
        try (Stream<String> lines = Files.lines(p)) {
            nonBlank = lines.filter(l -> !l.isBlank()).count();
        }
        System.out.println("Total lines: " + total);
        System.out.println("Non-blank: " + nonBlank);
    }
}

import java.nio.file.*;
public class App {
