import java.nio.file.*;
import java.util.stream.*;
public class App {
    public static void main(String[] args) throws Exception {
        // Create structure
        Files.createDirectories(Path.of("filetest", "data", "orders"));
        Files.createDirectories(Path.of("filetest", "data", "inventory"));
        Files.writeString(Path.of("filetest", "data", "orders", "march.csv"), "data");
        Files.writeString(Path.of("filetest", "data", "orders", "april.csv"), "data");
        Files.writeString(Path.of("filetest", "data", "inventory", "stock.csv"), "data");
        Files.writeString(Path.of("filetest", "data", "readme.txt"), "not csv");

        System.out.println("Found CSVs:");
        long count;
        try (Stream<Path> walk = Files.walk(Path.of("filetest"))) {
            count = walk
                .filter(Files::isRegularFile)
                .filter(p -> p.toString().endsWith(".csv"))
                .sorted()
                .peek(p -> System.out.println("  " + p))
                .count();
        }
        System.out.println("Total CSVs: " + count);
    }
}

