import java.nio.file.*;
import java.util.stream.*;
import java.util.*;
public class App {
    public static void main(String[] args) throws Exception {
        Path csv = Path.of("products.csv");
        Files.writeString(csv,
            "name,category,price\n" +
            "Mouse,Electronics,799\n" +
            "Keyboard,Electronics,1999\n" +
            "USB Hub,Accessories,499\n" +
            "Headphones,Electronics,2999\n" +
            "Monitor,Electronics,18999");

        try (Stream<String> lines = Files.lines(csv)) {
            lines
                .skip(1)  // skip header
                .map(line -> line.split(","))
                .filter(cols -> Integer.parseInt(cols[2]) > 1000)
                .sorted((a, b) -> Integer.compare(
                    Integer.parseInt(a[2]), Integer.parseInt(b[2])))
                .forEach(cols -> System.out.println(cols[0] + ": ₹" + cols[2]));
        }
    }
}

