exercises.expected_solution:
import java.nio.file.*;
import java.util.stream.*;
import java.util.*;
public class App {
    public static void main(String[] args) throws Exception {
        Path input = Path.of("input");
        Path done  = Path.of("done");
        Files.createDirectories(input);
        Files.createDirectories(done);

        Files.writeString(input.resolve("file1.txt"), "hello world java");
        Files.writeString(input.resolve("file2.txt"), "one two three four");
        Files.writeString(input.resolve("file3.txt"), "a b c d e");

        long moved = 0;
        try (Stream<Path> files = Files.list(input)) {
            List<Path> fileList = files
                .filter(Files::isRegularFile)
                .sorted()
                .collect(Collectors.toList());

            for (Path file : fileList) {
                String content = Files.readString(file);
                long wordCount = Arrays.stream(content.split("\\s+")).count();
                System.out.println("Processed: " + file.getFileName() + " (" + wordCount + " words)");
                Files.move(file, done.resolve(file.getFileName()),
                    StandardCopyOption.REPLACE_EXISTING);
                moved++;
            }
        }
        System.out.println("Moved " + moved + " files to done/");
    }
}

