import java.nio.file.*;
import java.util.*;
import java.util.stream.*;
public class App {
    static Set<String> filenames(Path dir) throws Exception {
        try (Stream<Path> s = Files.list(dir)) {
            return s.filter(Files::isRegularFile)
                    .map(p -> p.getFileName().toString())
                    .collect(Collectors.toSet());
        }
    }
    public static void main(String[] args) throws Exception {
        Path dir1 = Path.of("dir1"), dir2 = Path.of("dir2");
        Files.createDirectories(dir1);
        Files.createDirectories(dir2);
        for (String f : new String[]{"a.txt","b.txt","c.txt"}) Files.writeString(dir1.resolve(f), f);
        for (String f : new String[]{"b.txt","c.txt","d.txt"}) Files.writeString(dir2.resolve(f), f);

        Set<String> s1 = filenames(dir1);
        Set<String> s2 = filenames(dir2);

        Set<String> onlyIn1 = new TreeSet<>(s1); onlyIn1.removeAll(s2);
        Set<String> onlyIn2 = new TreeSet<>(s2); onlyIn2.removeAll(s1);

        System.out.println("Only in dir1:");
        onlyIn1.forEach(System.out::println);
        System.out.println("Only in dir2:");
        onlyIn2.forEach(System.out::println);
    }
}

