exercises.expected_solution:
import java.nio.file.*;
import java.util.*;
import java.util.stream.*;
public class App {
    public static void main(String[] args) throws Exception {
        Path csv = Path.of("orders.csv");
        Files.writeString(csv,
            "orderId,product,qty,unitPrice\n" +
            "ORD-001,Mouse,2,799\n" +
            "ORD-002,Keyboard,0,1999\n" +  // invalid: qty=0
            "ORD-003,USB Hub,5,499\n" +
            "ORD-004,Monitor,1,18999\n" +
            "ORD-005,Headphones,-1,2999\n" +  // invalid: negative qty
            "ORD-006,Webcam,3,4999");

        Files.createDirectories(Path.of("output"));

        List<String> valid = new ArrayList<>();
        List<String> errors = new ArrayList<>();
        valid.add("orderId,product,qty,unitPrice,total");
        long totalRevenue = 0;

        List<String> lines = Files.readAllLines(csv);
        for (int i = 1; i < lines.size(); i++) {  // skip header
            String[] cols = lines.get(i).split(",");
            int qty = Integer.parseInt(cols[2]);
            int price = Integer.parseInt(cols[3]);
            if (qty <= 0 || price <= 0) {
                errors.add("Row " + (i+1) + ": " + lines.get(i) + " [invalid qty or price]");
            } else {
                long total = (long) qty * price;
                totalRevenue += total;
                valid.add(lines.get(i) + "," + total);
            }
        }

        Files.write(Path.of("output", "valid.csv"), valid);
        Files.write(Path.of("output", "errors.txt"), errors);

        System.out.println("Valid orders: " + (valid.size() - 1));
        System.out.println("Invalid rows: " + errors.size());
        System.out.println("Total revenue: ₹" + totalRevenue);
        System.out.println("Output written to output/");
    }
}
